export const InfoTooltip = ({ isOpen, onClose, success, message }) => {
  return (
    <div className={`popup ${isOpen ? "popup_opened" : ""}`}>
      <div className="popup__content">
        <img src={success ? "Sucesso !" : "Algo deu errado"} />
        <p>{message}</p>
        <button onClick={onClose}>Fechar</button>
      </div>
    </div>
  );
};
